# Generated by openai (gpt-5.4)
# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from typing import Dict, List, Optional
from collections import Counter, defaultdict
from threading import Lock
import uvicorn
import os
import io

import numpy as np
from PIL import Image
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import StandardScaler
from sklearn.linear_model import LogisticRegression

app = FastAPI(title="Crowdsourced Data Labeling System")

class LabelSubmission(BaseModel):
    image_id: str = Field(..., min_length=1)
    annotator_id: str = Field(..., min_length=1)
    label: str = Field(..., min_length=1)

class ImageRecord(BaseModel):
    image_id: str
    filename: str

class AggregatedLabelResponse(BaseModel):
    image_id: str
    votes: Dict[str, int]
    aggregated_label: Optional[str]

class TrainResponse(BaseModel):
    trained_samples: int
    classes: List[str]

class PredictionResponse(BaseModel):
    image_id: str
    predicted_label: str
    probabilities: Dict[str, float]

UPLOAD_DIR = "uploaded_images"
os.makedirs(UPLOAD_DIR, exist_ok=True)

db_lock = Lock()
images: Dict[str, Dict] = {}
annotations: Dict[str, Dict[str, str]] = defaultdict(dict)
aggregated_labels: Dict[str, str] = {}
model_bundle = {
    "model": None,
    "classes": []
}

def compute_majority_vote(image_id: str) -> Optional[str]:
    label_map = annotations.get(image_id, {})
    if not label_map:
        return None
    counts = Counter(label_map.values())
    max_count = max(counts.values())
    winners = sorted([label for label, count in counts.items() if count == max_count])
    return winners[0] if winners else None

def get_votes(image_id: str) -> Dict[str, int]:
    label_map = annotations.get(image_id, {})
    return dict(Counter(label_map.values()))

def load_image_features(path: str) -> np.ndarray:
    img = Image.open(path).convert("RGB").resize((64, 64))
    arr = np.asarray(img, dtype=np.float32) / 255.0
    mean = arr.mean(axis=(0, 1))
    std = arr.std(axis=(0, 1))
    feat = np.concatenate([mean, std, arr.flatten()[::64]])
    return feat.astype(np.float32)

@app.post("/images", response_model=ImageRecord)
async def upload_image(image_id: str, file: bytes):
    with db_lock:
        if image_id in images:
            raise HTTPException(status_code=400, detail="image_id already exists")
        filename = f"{image_id}.bin"
        path = os.path.join(UPLOAD_DIR, filename)
        try:
            img = Image.open(io.BytesIO(file))
            img.verify()
        except Exception:
            raise HTTPException(status_code=400, detail="invalid image bytes")
        with open(path, "wb") as f:
            f.write(file)
        images[image_id] = {"filename": path}
        return ImageRecord(image_id=image_id, filename=path)

@app.post("/labels")
def submit_label(submission: LabelSubmission):
    with db_lock:
        if submission.image_id not in images:
            raise HTTPException(status_code=404, detail="image not found")
        annotations[submission.image_id][submission.annotator_id] = submission.label
        agg = compute_majority_vote(submission.image_id)
        if agg is not None:
            aggregated_labels[submission.image_id] = agg
        return {
            "status": "accepted",
            "image_id": submission.image_id,
            "annotator_id": submission.annotator_id,
            "label": submission.label,
            "aggregated_label": agg
        }

@app.get("/labels/{image_id}", response_model=AggregatedLabelResponse)
def get_aggregated_label(image_id: str):
    with db_lock:
        if image_id not in images:
            raise HTTPException(status_code=404, detail="image not found")
        votes = get_votes(image_id)
        agg = compute_majority_vote(image_id)
        return AggregatedLabelResponse(
            image_id=image_id,
            votes=votes,
            aggregated_label=agg
        )

@app.get("/images")
def list_images():
    with db_lock:
        return {
            "images": [
                {
                    "image_id": image_id,
                    "filename": data["filename"],
                    "aggregated_label": aggregated_labels.get(image_id),
                    "num_annotations": len(annotations.get(image_id, {}))
                }
                for image_id, data in images.items()
            ]
        }

@app.post("/train", response_model=TrainResponse)
def train_model():
    with db_lock:
        labeled_items = [
            (image_id, aggregated_labels[image_id])
            for image_id in images
            if image_id in aggregated_labels
        ]
        if len(labeled_items) < 2:
            raise HTTPException(status_code=400, detail="need at least 2 labeled images to train")

        X = []
        y = []
        for image_id, label in labeled_items:
            path = images[image_id]["filename"]
            try:
                feat = load_image_features(path)
            except Exception:
                continue
            X.append(feat)
            y.append(label)

        if len(set(y)) < 2:
            raise HTTPException(status_code=400, detail="need at least 2 classes to train")

        X = np.stack(X)
        y = np.array(y)

        clf = Pipeline([
            ("scaler", StandardScaler()),
            ("model", LogisticRegression(max_iter=1000))
        ])
        clf.fit(X, y)

        model_bundle["model"] = clf
        model_bundle["classes"] = sorted(list(set(y)))

        return TrainResponse(
            trained_samples=len(y),
            classes=model_bundle["classes"]
        )

@app.get("/predict/{image_id}", response_model=PredictionResponse)
def predict(image_id: str):
    with db_lock:
        if image_id not in images:
            raise HTTPException(status_code=404, detail="image not found")
        if model_bundle["model"] is None:
            raise HTTPException(status_code=400, detail="model not trained")
        path = images[image_id]["filename"]
        try:
            feat = load_image_features(path).reshape(1, -1)
        except Exception:
            raise HTTPException(status_code=400, detail="failed to load image features")

        model = model_bundle["model"]
        pred = model.predict(feat)[0]
        probs_arr = model.predict_proba(feat)[0]
        probs = {
            cls: float(prob)
            for cls, prob in zip(model.classes_, probs_arr)
        }
        return PredictionResponse(
            image_id=image_id,
            predicted_label=str(pred),
            probabilities=probs
        )

@app.get("/health")
def health():
    return {"status": "ok"}

if __name__ == "__main__":
    uvicorn.run(app, host="0.0.0.0", port=8000)